import {
  forwardRef,
  useId,
  useState,
  useCallback,
  useRef,
  useLayoutEffect,
  useImperativeHandle,
} from "react";
import {
  type TextAreaProps as AriaTextAreaProps,
  TextArea as AriaTextArea,
} from "react-aria-components";
import * as styles from "./Textarea.css";
import clsx from "clsx";
import { Hint } from "../Hint";
import type { TextareaValidation } from "./Textarea.config";

/**
 * Function to render the character count label
 * Receives the remaining character count as argument
 */
export type TextareaCharacterCountLabel = (
  remainingCharacters: number
) => string;

interface TextareaCustomProps {
  /**
   * The validation state of the textarea
   */
  validation?: TextareaValidation | undefined;

  /**
   * Whether the textarea should automatically resize based on content
   * When true, the textarea grows with content instead of showing a scrollbar
   * @default false
   */
  autoResize?: boolean;
}

// Props when maxLength is provided - requires characterCountLabel
interface TextareaWithMaxLength extends TextareaCustomProps {
  /**
   * Maximum number of characters allowed
   */
  maxLength: number;

  /**
   * Function to render the character count label
   * Required when maxLength is provided
   */
  characterCountLabel: TextareaCharacterCountLabel;
}

// Props when maxLength is not provided
interface TextareaWithoutMaxLength extends TextareaCustomProps {
  maxLength?: never;
  characterCountLabel?: never;
}

export type TextareaProps = Omit<
  AriaTextAreaProps,
  keyof TextareaCustomProps | "maxLength" | "aria-invalid"
> &
  (TextareaWithMaxLength | TextareaWithoutMaxLength);

export const Textarea = forwardRef<HTMLTextAreaElement, TextareaProps>(
  (
    {
      validation,
      autoResize = false,
      maxLength,
      characterCountLabel,
      className,
      id,
      onChange,
      "aria-describedby": ariaDescribedBy,
      ...props
    },
    ref
  ) => {
    const internalRef = useRef<HTMLTextAreaElement>(null);
    useImperativeHandle(
      ref,
      () => internalRef.current as HTMLTextAreaElement,
      []
    );

    // Auto-resize: adjust height based on content
    useLayoutEffect(() => {
      const textarea = internalRef.current;
      if (!textarea || !autoResize) return;

      const adjustHeight = () => {
        textarea.style.height = "auto";
        textarea.style.height = `${textarea.scrollHeight}px`;
      };

      // Adjust on mount and value changes
      adjustHeight();

      // Listen for native input events for uncontrolled mode
      textarea.addEventListener("input", adjustHeight);
      return () => textarea.removeEventListener("input", adjustHeight);
    }, [autoResize, props.value]);

    // Generate unique ID for character count accessibility
    const generatedId = useId();
    const textareaId = id ?? generatedId;
    const characterCountId =
      maxLength !== undefined ? `${textareaId}-character-count` : undefined;

    // Merge aria-describedby: combine passed-in value with character count ID
    const mergedAriaDescribedBy =
      [ariaDescribedBy, characterCountId].filter(Boolean).join(" ") ||
      undefined;

    const getValueLength = (val: unknown): number => {
      if (val == null) return 0;
      return String(val).length;
    };

    // Calculate initial length, capped at maxLength since browser trims the value
    const rawInitialLength =
      props.value != null
        ? getValueLength(props.value)
        : getValueLength(props.defaultValue);
    const initialLength =
      maxLength !== undefined
        ? Math.min(rawInitialLength, maxLength)
        : rawInitialLength;

    const [internalLength, setInternalLength] = useState(initialLength);

    // For controlled mode, use the value prop length; for uncontrolled, use internal state
    // Cap at maxLength since browser enforces the limit on actual textarea content
    const isControlled = props.value != null;
    const rawCurrentLength = isControlled
      ? getValueLength(props.value)
      : internalLength;
    const currentLength =
      maxLength !== undefined
        ? Math.min(rawCurrentLength, maxLength)
        : rawCurrentLength;

    const remainingCharacters =
      maxLength !== undefined ? maxLength - currentLength : 0;

    const handleChange = useCallback(
      (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        setInternalLength(e.target.value.length);
        onChange?.(e);
      },
      [onChange]
    );

    const isInvalid = validation === "invalid";

    const textareaClasses = clsx(
      styles.textarea({
        autoResize,
      }),
      className
    );

    return (
      <div className={styles.textareaWrapper}>
        <AriaTextArea
          ref={internalRef}
          id={textareaId}
          className={textareaClasses}
          data-validation={validation ?? undefined}
          aria-invalid={isInvalid || undefined}
          aria-describedby={mergedAriaDescribedBy}
          onChange={handleChange}
          {...(maxLength !== undefined && { maxLength })}
          {...props}
        />
        {maxLength !== undefined && characterCountLabel !== undefined && (
          <Hint id={characterCountId} aria-live="polite">
            {characterCountLabel(remainingCharacters)}
          </Hint>
        )}
      </div>
    );
  }
);

Textarea.displayName = "Textarea";
